// Extract line 110
const lines = sourcegraphContent.split('\n');
const line110 = lines[2];
console.log('Line 110 from Sourcegraph response:');
console.log('Raw:', line110);
console.log('');

// Extract the string
const match = line110.match(/ESCAPED_EXPAND:\s*'([^']*?)'/);
if (match) {
  const stringLiteral = match[1];
  console.log('String literal (between quotes):', stringLiteral);
  console.log('');
  console.log('Characters:');
  for (let i = 0; i < stringLiteral.length; i++) {
    const char = stringLiteral[i];
    const code = stringLiteral.charCodeAt(i);
    console.log(`  [${i}]: code=${code} (char: '${char}')`);
  }
  console.log('');
  console.log('Interpretation: starts with', stringLiteral.charCodeAt(0) === 92 ? 'backslash' : 'not backslash');
}
